import dspy
import vex

disclaimer_template = "This is not personalized investment advice. Past performance doesn't guarantee future results. Consult a qualified advisor."

class InvestmentAdvisor(dspy.Module):
    def __init__(self):
        super().__init__()
        self.recommendation = dspy.ChainOfThought('portfolio,risk_tolerance -> asset,rationale')

    def forward(self, portfolio, risk_tolerance):
        with vex.verify({
            'sec_regbi': f'disclaimer_template in final_advice',
            'no_guarantees': 'not "guaranteed" in rationale and not "certain" in rationale',
            'risk_warning': '"consider your risk tolerance" in final_advice',
            'no_pii': 'not any(x in portfolio for x in ["ssn","account"])'
        }):
            rec = self.recommendation(portfolio=portfolio, risk_tolerance=risk_tolerance)
            final_advice = f"Recommendation: Invest in {rec.asset}. Rationale: {rec.rationale}. {disclaimer_template}"
        return {'advice': final_advice, 'raw': rec}

advisor = InvestmentAdvisor()
rec = advisor('balanced ETF portfolio', 'moderate')
